def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 7) / (a * b * 1.1 + 1)
                    priority += factor * np.sin(ratio * b / (a + 2)) ** 2
            priority += (np.exp(ratio - 10) * np.cos(ratio * 1.3)) ** 2
        elif 7 < ratio <= 10:
            total = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 1.5)
                    total += np.tanh(term) * 1.5
            priority += total + np.log(ratio) * 15 - np.tanh(ratio - 7) * 3
        elif 4 <= ratio <= 7:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 4) ** r) / (r * 2.1) * np.sin(r * ratio * 1.2)
            priority = (s * np.sin(9 * ratio)) - np.log(ratio) * 9 + np.tanh(5 * (7 - ratio)) * 2.5
        elif 2 <= ratio < 4:
            s = 0
            for n in range(1, 12):
                s += ((4 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1.9) ** m) / (m * 1.2)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((2 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 15):
                s += ((1 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 2) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for m in range(1, 10):
                priority += ((1 - ratio) ** m) / (m * 8) * np.cos(item * m * 1.4)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 20):
                s += ((0.5 - ratio) ** t) / (t * 7) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 1) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 1.8) * 6
            for u in range(1, 12):
                priority += ((0.5 - ratio) ** u) / (u * 10) * np.cos(item * u * 1.3)
        else:
            s = 0
            for v in range(1, 15):
                s += ((0.2 - ratio) ** v) / (v * 8) * np.cos(v * item * 1.0)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 2.5) * 7
            for w in range(1, 10):
                priority += ((0.2 - ratio) ** w) / (w * 9) * np.sin(item * w * 0.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        if i % 2 == 0 and bin_cap < item * 0.9:
            priority += np.tanh(ratio * i) * 2
        elif i % 3 == 0 and bin_cap > item * 2:
            priority -= np.tanh(ratio * i) * 2
        priorities[i] = priority
    return priorities
